fn install_cron() -> Result<()> {
    fs::create_dir_all(env::current_dir()?.join("work_docs/cron_logs"))?;
    let existing = read_crontab()?;
    let next = format!(
        "{}\n\n{}\n",
        strip_existing_block(&existing).trim_end(),
        cron_block()?
    );
    write_crontab(next.trim_start())?;
    println!("installed CRCL Codex cron block");
    println!("{}", cron_block()?);
    Ok(())
}

fn remove_cron() -> Result<()> {
    let existing = read_crontab()?;
    let next = format!("{}\n", strip_existing_block(&existing).trim_end());
    write_crontab(next.trim_start())?;
    println!("removed CRCL Codex cron block");
    Ok(())
}

fn cron_block() -> Result<String> {
    let root = env::current_dir()?;
    let log_dir = root.join("work_docs/cron_logs");
    let mut lines = vec![
        CRON_BEGIN.to_string(),
        "SHELL=/bin/zsh".to_string(),
        format!("PATH={}", cron_path()),
        format!("CRCL_ROOT={}", root.display()),
        format!(
            "CRCL_CODEX_SAFE_MODE={}",

            history_limit,
            format,
            no_collect,
        } => {
            run_decision_pack(DecisionPackRequest {
                db: &db,
                database: &cli.database,
                timeout_secs: cli.timeout_secs,
                user_agent: cli.user_agent,
                workflow,
                limit,
                history_limit,
                format,
                no_collect,
            })
            .await?;
        }
        Command::AgentRun {
            workflow,
            limit,
            history_limit,
            format,
            no_collect,
            save,
            out_dir,
            current_position_pct,
        } => {
            run_agent_run(
                DecisionPackRequest {
                    db: &db,
                    database: &cli.database,
                    timeout_secs: cli.timeout_secs,
                    user_agent: cli.user_agent,
                    workflow,
                    limit,
                    history_limit,
                    format,
                    no_collect,
                },
                save,
                out_dir,
                current_position_pct,
            )
            .await?;
        }
        Command::FullAnalysis {
            format,
            save,
            out_dir,
            work_docs_dir,
        } => {
            full_analysis::run(
                &db,
                &cli.database,
                full_analysis::FullAnalysisOptions {
                    format,
                    save,
                    out_dir,
                    work_docs_dir,
                },
            )?;
        }
        Command::Cron { command } => {
            cron_runner::handle(command)?;
        }
        Command::Summary => {
            let summary = db.summary()?;
            println!("collection_batches={}", summary.collection_batches);
            println!("source_runs={}", summary.source_runs);
            println!("observations={}", summary.observations);
            println!("filings={}", summary.filings);
            println!("events={}", summary.events);
            println!("missing_items={}", summary.missing_items);
        }
        Command::Missing => {
            for item in db.missing_items()? {
                println!(
                    "{} | {} | {} | {}",
                    item.priority, item.metric_code, item.metric_name, item.reason
                );
            }
        }
    }

    Ok(())
}

async fn run_decision_pack(request: DecisionPackRequest<'_>) -> Result<()> {
    let format = request.format;
    let packet_request = workflow_packet_request(request).await?;

    workflows::print_workflow_packet(packet_request, format)
}

async fn run_agent_run(
    request: DecisionPackRequest<'_>,
    save: bool,
    out_dir: PathBuf,
    current_position_pct: Option<f64>,
) -> Result<()> {
    let format = request.format;
    let packet_request = workflow_packet_request(request).await?;
    let packet = workflows::build_workflow_packet(packet_request)?;
    agent_runner::run_agent_packet(
        packet,
        agent_runner::AgentRunOptions {
            format,
            save,
            out_dir,
            current_position_pct,
        },
    )
}

async fn workflow_packet_request<'a>(
    request: DecisionPackRequest<'a>,
) -> Result<WorkflowPacketRequest<'a>> {
    let collector_run = collect_for_workflow(&request).await?;
    Ok(WorkflowPacketRequest {
        db: request.db,
        database: request.database,
        workflow: request.workflow,
        limit: request.limit,
        history_limit: request.history_limit,
        collector_run,
    })
}

